const sources = $('Build Claude Payload').all();
return $input.all().map(({ json: response }, i) => {
  const dedupe_id = sources[i] && sources[i].json ? sources[i].json.dedupe_id : null;
  const rawText = response.content?.[0]?.text ?? '';
  const cleaned = rawText.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
  let parsed;
  try {
    parsed = JSON.parse(cleaned);
  } catch (e) {
    parsed = { error: 'parsing_failed', reason: 'Claude response was not valid JSON', raw_text: rawText };
  }
  return { json: { ...parsed, dedupe_id } };
});

const out = [];
for (const { json: item } of $input.all()) {
  const isOutlook = item.internetMessageId !== undefined || (item.body && item.body.content !== undefined) || item.bodyPreview !== undefined;
  let emailBody = '';
  let dedupe_id = '';
  if (isOutlook) {
    const bodyContent = item.body && item.body.content ? item.body.content : (item.bodyPreview || '');
    emailBody = bodyContent;
    if (bodyContent.indexOf('<') !== -1) {
      emailBody = bodyContent
        .replace(/<[^>]+>/g, ' ')
        .replace(/&nbsp;/g, ' ')
        .replace(/&amp;/g, '&')
        .replace(/&lt;/g, '<')
        .replace(/&gt;/g, '>')
        .replace(/\s+/g, ' ')
        .trim();
    }
    dedupe_id = 'bbva:' + (item.internetMessageId || item.id || emailBody.slice(0, 120));
  } else {
    emailBody = item.text || '';
    if (!emailBody && item.html) {
      emailBody = item.html
        .replace(/<[^>]+>/g, ' ')
        .replace(/&nbsp;/g, ' ')
        .replace(/\s+/g, ' ')
        .trim();
    }
    if (!emailBody && item.snippet) emailBody = item.snippet;
    dedupe_id = 'diners:' + (item.id || item.threadId || emailBody.slice(0, 120));
  }
  if (!emailBody || !emailBody.trim()) continue;
  out.push({ json: { ...item, emailBody, dedupe_id } });
}
return out;

const emails = $('Extract Body').all();
const checks = $input.all();
return checks.map((c, i) => {
  const rows = c.json?.results?.[0]?.response?.result?.rows ?? [];
  const base = emails[i] ? emails[i].json : {};
  return { json: { ...base, _seen: rows.length > 0 } };
});

return $input.all().map(({ json: item }) => {
  const p = item.payload || {};
  const system = p.system || '';
  const userMsg = (p.messages && p.messages[0] && p.messages[0].content) || item.emailBody || '';
  return { json: { dedupe_id: item.dedupe_id, openai: { model: 'gpt-4o-mini', max_tokens: 1024, response_format: { type: 'json_object' }, messages: [ { role: 'system', content: system }, { role: 'user', content: userMsg } ] } } };
});

