const t = (v) => (v == null ? { type: 'null' } : { type: 'text', value: String(v) });
const f = (v) => (v == null || isNaN(Number(v)) ? { type: 'null' } : { type: 'float', value: Number(v) });
return $input.all().map(({ json: j }) => {
  const dedupe_id = j.dedupe_id;
  let tursoBody;
  if (j.error) {
    tursoBody = { requests: [
      { type: 'execute', stmt: { sql: 'INSERT OR IGNORE INTO errors (dedupe_id,error,reason,raw_text) VALUES (?,?,?,?)', args: [ t(dedupe_id), t(j.error), t(j.reason), t(j.raw_text) ] } },
      { type: 'close' },
    ] };
  } else {
    const pfx = String(dedupe_id).split(':')[0];
    const source = pfx === 'bbva' ? 'mail-bbva' : (pfx === 'interbank' ? 'manual-interbank' : 'mail-diners');
    const category = j.category || 'other';
    tursoBody = { requests: [
      { type: 'execute', stmt: { sql: 'INSERT OR IGNORE INTO categories (name) VALUES (?)', args: [ t(category) ] } },
      { type: 'execute', stmt: { sql: 'INSERT OR IGNORE INTO transactions (dedupe_id,date,time,bank,card_last4,amount,currency,merchant,merchant_clean,transaction_type,channel,confidence,raw_text,source,category) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)', args: [ t(dedupe_id), t(j.date), t(j.time), t(j.bank), t(j.card_last4), f(j.amount), t(j.currency), t(j.merchant), t(j.merchant_clean), t(j.transaction_type), t(j.channel), t(j.confidence), t(j.raw_text), t(source), t(category) ] } },
      { type: 'close' },
    ] };
  }
  return { json: { ...j, tursoBody } };
});

const SYSTEM_PROMPT = `You extract transactions from a screenshot of the Interbank (Peru) mobile banking app transaction list.

Return ONLY a JSON array (no prose, no markdown fences). Each element is one transaction row:
{
  "date": "YYYY-MM-DD",
  "time": "HH:MM" or null,
  "bank": "Interbank",
  "card_last4": null,
  "amount": 123.45,
  "currency": "PEN" | "USD" | "EUR",
  "merchant": "row title exactly as shown",
  "merchant_clean": "human-readable name",
  "transaction_type": "purchase" | "withdrawal" | "online" | "recurring" | "refund" | "unknown",
  "channel": "in_store" | "online" | "atm" | "unknown",
  "raw_text": "the visible row text",
  "confidence": "high" | "medium" | "low",
  "category": "lowercase slug"
}

Each row has a merchant title, a date line, and an amount on the right.

DATE LINE: Spanish, e.g. "Jue 25 Jun 6:19 pm" (weekday DD MonthAbbrev h:mm am/pm). Months: Ene=01 Feb=02 Mar=03 Abr=04 May=05 Jun=06 Jul=07 Ago=08 Sep/Set=09 Oct=10 Nov=11 Dic=12. The year is NOT shown — infer it: use the year of today (given in the user message); if that places the date in the future, use the previous year. Output YYYY-MM-DD.

TIME: convert am/pm to 24h HH:MM. "6:19 pm"->"18:19", "8:49 am"->"08:49", "12:10 am"->"00:10". If no time, null.

AMOUNT: the number on the right. "S/"->PEN, "US$"->USD, "€"->EUR. A minus sign means debit — ALWAYS output a POSITIVE number, never negate.

"En proceso" under an amount means pending — still include the row; transaction_type default "purchase".

merchant_clean: Title Case the merchant; map known brands (STEAMGAMES->Steam, HETZNER->Hetzner, NETFLIX->Netflix, SPOTIFY->Spotify, UBER->Uber, RAPPI->Rappi, PEDIDOSYA->PedidosYa, TOTTUS->Tottus, PVEA/PLAZA VEA->Plaza Vea, VIVANDA->Vivanda); drop leading store codes/numbers when obvious.

channel: physical stores/gas stations->in_store; .com/app/games/online services->online; cajero/ATM->atm; else unknown.
category: one of groceries, dining, transport, subscriptions, shopping, health, utilities, entertainment, cash, transfer, fees; else "other". Fuel (GNV, grifo, estacion, quilca gnv)->transport. Steam/games->entertainment. Supermarkets (Plaza Vea, Vivanda, Tottus, Wong)->groceries.

confidence: high if fully legible; medium if you inferred the year or cleaned aggressively; low if amount/merchant unclear.

If the image shows no transaction rows, return [].`;

const TODAY = new Date().toISOString().slice(0, 10);
const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary || {};
  for (const key of Object.keys(bin)) {
    const meta = bin[key];
    if (!meta) continue;
    const buf = await this.helpers.getBinaryDataBuffer(i, key);
    const b64 = buf.toString('base64');
    if (!b64) continue;
    out.push({ json: { payload: {
      model: 'claude-sonnet-4-6',
      max_tokens: 2048,
      system: SYSTEM_PROMPT,
      messages: [{ role: 'user', content: [
        { type: 'image', source: { type: 'base64', media_type: meta.mimeType || 'image/jpeg', data: b64 } },
        { type: 'text', text: 'Today is ' + TODAY + '. Extract every transaction row visible in this Interbank app screenshot as a JSON array.' }
      ] }]
    } } });
  }
}
return out;

function hash(s){let h=5381;for(let i=0;i<s.length;i++)h=((h*33)^s.charCodeAt(i))>>>0;return h.toString(16);}
const out = [];
for (const { json: response } of $input.all()) {
  const rawText = response.content && response.content[0] && response.content[0].text ? response.content[0].text : '';
  const cleaned = rawText.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
  let arr;
  try { arr = JSON.parse(cleaned); } catch (e) { arr = []; }
  if (!Array.isArray(arr)) arr = (arr && typeof arr === 'object') ? [arr] : [];
  for (const tx of arr) {
    if (!tx || tx.error) continue;
    const key = [tx.merchant, tx.date, tx.time, tx.amount, tx.currency].map((x) => (x == null ? '' : String(x))).join('|');
    out.push({ json: { ...tx, bank: tx.bank || 'Interbank', dedupe_id: 'interbank:' + hash(key) } });
  }
}
return out;
